const e=[{id:"L05-ch-001",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["词汇","称谓"],block:"vocabulary",prompt:"选出正确的用法：",question:'"Mr." 的正确用法是？',options:["Mr. Smith（放在姓氏前）","Mr. John（放在名字前）","单独使用 Mr.","Mr（不加点号）"],correctIndex:0,explanation:`【社交礼仪】Mr. = 先生，必须放在姓氏(surname/family name)前面，不能放在名字前面。
【正确】Mr. Smith(史密斯先生) ✅
【错误】Mr. John(John是名不是姓) ❌ 应该说Mr. + 姓。
【对应】Miss(小姐，未婚), Mrs.(夫人，已婚), Ms.(女士，不指明婚姻状况)。`},{id:"L05-ch-002",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["词汇","形容词"],block:"vocabulary",prompt:"选出正确的中文意思：",question:'"nice" 在 "Nice to meet you" 中的意思是？',options:["美好的/高兴的","好的","新的","漂亮的"],correctIndex:0,explanation:`【词汇】nice = 美好的，令人愉快的。Nice to meet you. = 很高兴见到你。
【用法】nice是最常用的赞美形容词之一：a nice day(美好的一天), a nice person(一个好人)。
【注意】nice和good的区别：nice更强调"令人愉悦的"，good更强调"好的品质"。`},{id:"L05-ch-003",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["词汇","动词"],block:"vocabulary",prompt:"选出正确的中文意思：",question:'"meet" 是什么意思？',options:["遇见/认识","见面/会见","想念","帮助"],correctIndex:0,explanation:`【词汇】meet = 遇见/认识。Nice to meet you. = 很高兴认识你（初次见面用语）。
【搭配】meet a friend(见朋友), meet for lunch(约午饭)。
【区别】meet(第一次见面认识) ↔ see(已经认识的人见面)："Nice to meet you."(初次) vs "Nice to see you."(再次)。`},{id:"L05-ch-004",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["词汇","国籍词"],block:"vocabulary",prompt:'"French" 的正确意思是？',question:"She is French. = ?",options:["她是法国人","她说法语","她住在法国","她喜欢法国"],correctIndex:0,explanation:`【国籍词】French = 法国的/法国人的/法语。
【用法】①She is French.(她是法国人) ②She speaks French.(她说法语) ③French wine(法国葡萄酒)。
【对比】France是"法国"(国家名)，French是"法国的/法国人"（形容词/名词）。所有国籍词首字母都要大写！`},{id:"L05-ch-005",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["词汇","国籍词"],block:"vocabulary",prompt:'"German" 的正确意思是？',question:"选出正确的表述：",options:["德国的/德国人","德国（国家）","德语","德国制造"],correctIndex:0,explanation:`【词汇】German = 德国的/德国人。注意Germany才是"德国"(国家名)。
【对比】German(德国人) ≠ Germany(德国)。He is German. = 他是德国人。He is from Germany. = 他来自德国。
【系列】French(法国), German(德国), Japanese(日本), Korean(韩国), Chinese(中国)。`},{id:"L05-ch-006",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["词汇","国籍词"],block:"vocabulary",prompt:'"Japanese" 和 "Chinese" 的共同特点是？',question:"选出正确说法：",options:["都以-ese结尾，单复数同形","都以-ish结尾","都以-an结尾","都来自欧洲"],correctIndex:0,explanation:`【国籍词规律】以-ese结尾的国籍词：Chinese(中国), Japanese(日本), Portuguese(葡萄牙)。这些词单数和复数形式相同。
【对比】以-ish结尾：English, British, Swedish。以-an结尾：American, Korean, German。
【要点】Chinese和Japanese可以同时指"某国人"和"某国的"，没有特殊的复数形式！`},{id:"L05-ch-007",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["词汇","副词"],block:"vocabulary",prompt:'"too" 在句中的正确位置是？',question:'"He is German, ___." 填入正确位置：',options:["句末（逗号后）","be动词前","形容词前","句首"],correctIndex:0,explanation:`【副词位置】too表示"也"，通常放在句末，前面加逗号。
【例句】She is French. He is German, too. = 她是法国人。他也是德国人。
【同义词】also(也)更正式，放在be动词后：He is also German. too更口语化，放在句末。`},{id:"L05-ch-008",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["语法","第三人称"],block:"grammar",prompt:"选出正确的be动词：",question:"She ___ French. He ___ German.",options:["is / is","are / is","is / am","am / is"],correctIndex:0,explanation:`【语法规则】第三人称单数(he/she/it)统一用is。
【口诀】I用am，you用are，is连着he/she/it，单数名词用is，复数全部都用are。
【本题】She(第三人称单数)→is，He(第三人称单数)→is。`},{id:"L05-ch-009",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["词汇","形容词"],block:"vocabulary",prompt:'"new" 在课文中的意思是？',question:'"She is a new student." 中 new 的意思是？',options:["新来的","年轻的","好的","聪明的"],correctIndex:0,explanation:`【词汇】new = 新的。a new student = 一个新来的学生。
【反义词】new(新的) ↔ old(旧的/老的)。
【搭配】a new car(新车), a new dress(新裙子), new friend(新朋友)。注意new放在名词前面修饰名词。`},{id:"L05-ch-010",type:"choice",lessonGroup:"lesson-05-06",lessonNumber:6,difficulty:"hard",tags:["词汇","一词多义"],block:"vocabulary",prompt:'"make" 在 "What make is it?" 中的意思是？',question:"选出正确解释：",options:["品牌/牌子","制作","让/使","型号"],correctIndex:0,explanation:`【一词多义】make通常作动词表示"制作"(I make a cake.)，但在"What make is it?"中作名词表示"品牌/牌子"。
【句型】What make is your car? = 你的车是什么牌子的？
【回答】It is a Toyota/Volvo/BMW. = 它是丰田/沃尔沃/宝马。`},{id:"L05-fl-001",type:"fill",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["语法","be动词"],block:"grammar",prompt:"用正确的be动词形式填空：",sentence:"I ___ a student. She ___ a teacher.",answer:"am, is",acceptableAnswers:["am is","am,is","am, is"],hint:"I对应am，she对应is。",explanation:`【be动词对照】I→am, you→are, he/she/it→is, we→are, they→are。
【技巧】英语中每个主语都有固定的be动词搭档，不能混用。说话前先想主语是谁，再选对应的be动词。`},{id:"L05-fl-002",type:"fill",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["词汇","国籍"],block:"vocabulary",prompt:"填写正确的国籍词：",sentence:"I am from China. I am ___.（中国的）",answer:"Chinese",acceptableAnswers:["Chinese"],hint:"China对应哪个国籍形容词？注意首字母大写。",explanation:`【国籍对应】国家→国籍：China→Chinese, Japan→Japanese, France→French, Germany→German, Korea→Korean。
【注意】①国籍词首字母必须大写 ②Chinese的单复数同形：one Chinese, two Chinese。`},{id:"L05-fl-003",type:"fill",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["交际用语","问候"],block:"vocabulary",prompt:"初次见面时，完成这段对话：",sentence:`— Nice to ___ you.
— Nice to meet you, ___.`,answer:"meet, too",acceptableAnswers:["meet too","meet,too","meet, too"],hint:'第一个空是"遇见"，第二个空是"也"。',explanation:`【初次见面标准对话】A: Nice to meet you. → B: Nice to meet you, too.
【要点】①too表示"也"，放在句末 ②双方都说同样的话，非常对称。
【对比】How do you do?(正式)→回答也是How do you do? 注意不要把两种问候搞混。`},{id:"L05-fl-004",type:"fill",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["词汇","问候"],block:"vocabulary",prompt:"早上见到老师应该怎么问候？",sentence:"Good ___, Miss Li.",answer:"morning",acceptableAnswers:["morning"],hint:"早上好的英文。",explanation:`【时间问候】早上→Good morning. 下午→Good afternoon. 晚上→Good evening. 睡前→Good night.
【用法】Good morning后可以加称呼：Good morning, Mr. Zhang. / Good morning, class.
【文化】英语国家中这些时间问候非常常用，比直接说Hello更正式礼貌。`},{id:"L05-fl-005",type:"fill",lessonGroup:"lesson-05-06",lessonNumber:6,difficulty:"hard",tags:["词汇","句型"],block:"vocabulary",prompt:"根据上下文填空：",sentence:`A: What ___ is your car?
B: It is a Volvo.`,answer:"make",acceptableAnswers:["make"],hint:'询问"品牌/牌子"用哪个词？',explanation:`【句型】What make is...? = ...是什么牌子的？
【用法】make在这里是名词(品牌)，不是动词(制作)。
【场景】在讨论汽车、电器、电子产品时，常用这个句型问品牌。`},{id:"L05-fl-006",type:"fill",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["语法","主系表"],block:"grammar",prompt:"用所给词的正确形式填空：",sentence:"He ___ (be) a new student. He ___ (be) not French.",answer:"is, is",acceptableAnswers:["is is","is,is","is, is"],hint:"he后面永远跟哪个be动词？",explanation:`【语法】he是第三人称单数，be动词固定用is。不管是肯定句还是否定句都不变。
【完整句】He is a new student. He is not French.
【扩展】is not可以缩写为isn't。He isn't French. = 他不是法国人。`},{id:"L05-tr-001",type:"translate",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["句型","介绍"],block:"sentence",prompt:"请翻译成英文：",sourceText:"这位是Sophie小姐。她是法国人。",direction:"cn2en",acceptableAnswers:["This is Miss Sophie. She is French.","This is Miss Sophie. She's French."],keywords:["this","is","miss","she","french"],explanation:`【介绍句型】①This is + 姓名/称谓 = 介绍某人 ②She/He is + 国籍 = 说明国籍。
【称谓】Miss用于未婚女性，Mrs.用于已婚女性，Mr.用于男性。
【语序】英语和中文一样，先介绍人，再补充说明信息。`},{id:"L05-tr-002",type:"translate",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["句型","问候"],block:"sentence",prompt:"请翻译成英文：",sourceText:"很高兴认识你。我也很高兴认识你。",direction:"cn2en",acceptableAnswers:["Nice to meet you. Nice to meet you, too.","Nice to meet you. Nice to meet you too."],keywords:["nice","meet","you","too"],explanation:`【初次见面对话】A先说Nice to meet you. → B回答Nice to meet you, too.
【要点】too放在句末，用逗号隔开。对话中双方说几乎相同的话，这是对称性的表达习惯。
【提醒】第一次见面说meet，以后再见要说see—Nice to see you again!`},{id:"L05-tr-003",type:"translate",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["句型","国籍"],block:"sentence",prompt:"请翻译成英文：",sourceText:"我不是中国人，我是日本人。",direction:"cn2en",acceptableAnswers:["I am not Chinese. I am Japanese.","I'm not Chinese. I'm Japanese."],keywords:["not","chinese","japanese"],explanation:`【否定+肯定组合】先用否定排除→再用肯定说明。
【结构】I am NOT Chinese.(否定) + I AM Japanese.(肯定，am重读以形成对比)。
【口语】口语中常把am not缩写成'm not，但不说amn't（没有这种缩写）。`},{id:"L05-tr-004",type:"translate",lessonGroup:"lesson-05-06",lessonNumber:6,difficulty:"medium",tags:["句型","品牌"],block:"sentence",prompt:"请翻译成英文：",sourceText:"你的车是什么牌子的？是沃尔沃。",direction:"cn2en",acceptableAnswers:["What make is your car? It's a Volvo.","What make is your car? It is a Volvo."],keywords:["what","make","car","volvo"],explanation:`【品牌问答】问：What make is your car? (你的车什么牌子？) 答：It's a Volvo.
【语法】①make作名词=品牌 ②回答中用a+品牌名，因为是一辆车。
【扩展】还可以说What brand is your car? 但make更地道。`},{id:"L05-tr-005",type:"translate",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"hard",tags:["场景对话"],block:"sentence",prompt:"请翻译成英文（介绍朋友认识的场景）：",sourceText:"早上好。这位是王先生，他是中国人。这位是Sophie小姐，她是法国人。很高兴认识你。",direction:"cn2en",acceptableAnswers:["Good morning. This is Mr. Wang. He is Chinese. This is Miss Sophie. She is French. Nice to meet you.","Good morning. This is Mr. Wang, he is Chinese. This is Miss Sophie, she is French. Nice to meet you."],keywords:["good","morning","this","is","chinese","french","nice","meet"],explanation:`【综合场景】这段对话融合了多种句型：①时间问候 ②介绍他人 ③说明国籍 ④初次见面问候。
【要点】①Mr.+姓氏(王) ②Miss+名字(Sophie) ③国籍词首字母大写。
【结构】先问候→介绍A→说明A信息→介绍B→说明B信息→互相问候。`},{id:"L05-tr-006",type:"translate",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["词汇","国籍"],block:"vocabulary",prompt:"请翻译成中文，注意国籍词：",sourceText:"Mr. Smith is American. Miss Li is Chinese. They are both teachers.",direction:"en2cn",acceptableAnswers:["史密斯先生是美国人。李小姐是中国人。他们都是老师。"],keywords:["美国人","中国人","老师"],explanation:`【翻译要点】①American→美国人 ②Chinese→中国人 ③both表示"两者都"。
【句型】They are both + 职业 = 他们两个都是...。both放在be动词后面、职业词前面。
【语法】both的位置：They are both teachers. ✅ They both are teachers. ❌（不推荐此语序）。`},{id:"L05-ro-001",type:"reorder",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["句型","介绍"],block:"sentence",prompt:"排列成正确的英文句子：",words:["This","is","Miss","Sophie","Dupont","."],correctOrder:[0,1,2,3,4,5],correctSentence:"This is Miss Sophie Dupont.",explanation:`【介绍句型】This + is + 称谓(Miss) + 全名。
【称谓顺序】Miss(小姐) + 名字(Sophie) + 姓氏(Dupont)。西方人名在前姓在后。
【注意】如果是Mr.，后面只能用姓氏，不能用全名：Mr. Dupont ✅ Mr. John Dupont ❌（太正式的场景除外）。`},{id:"L05-ro-002",type:"reorder",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["句型","国籍"],block:"sentence",prompt:"排列成正确的英文句子：",words:["She","is","French",",","too","."],correctOrder:[0,1,2,3,4,5],correctSentence:"She is French, too.",explanation:`【句式】She is French, too. = 她也是法国人。
【too的位置】①句末加逗号 ②放在be动词后面也可以：She is too French. ❌（这样意思就变了！She is also French. ✅）。
【规则】too放句末是最自然的口语表达。`},{id:"L05-ro-003",type:"reorder",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["句型","问候"],block:"sentence",prompt:"排列成正确的英文句子：",words:["Nice","to","meet","you",",","too","."],correctOrder:[0,1,2,3,4,5,6],correctSentence:"Nice to meet you, too.",explanation:`【固定表达】Nice to meet you, too. = 我也很高兴认识你。
【结构】Nice to meet you(核心部分) + ,(逗号) + too(也)。
【变化】去掉too就是主动问候，加上too就是回应对方的问候。`},{id:"L05-ro-004",type:"reorder",lessonGroup:"lesson-05-06",lessonNumber:6,difficulty:"medium",tags:["句型","品牌"],block:"sentence",prompt:"排列成正确的英文句子：",words:["What","make","is","your","car","?"],correctOrder:[0,1,2,3,4,5],correctSentence:"What make is your car?",explanation:`【特殊疑问句】What make + is + 限定词 + 名词? = ...是什么牌子的？
【结构】What make(什么品牌)作为疑问短语，放在句首，后面接is/are。
【扩展】What colour is your car?(什么颜色), What size is your shirt?(什么尺码)。`},{id:"L05-ro-005",type:"reorder",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"hard",tags:["句型","综合"],block:"sentence",prompt:"排列成正确的英文句子：",words:["Good","morning",".","I","am","a","new","student","."],correctOrder:[0,1,2,3,4,5,6,7,8],correctSentence:"Good morning. I am a new student.",explanation:`【综合表达】①时间问候 ②自我介绍。
【语法】a new student → a + 形容词(new) + 名词(student)。冠词a放在名词短语的最前面。
【课堂场景】上学第一天对老师的自我介绍，非常实用的表达！`},{id:"L05-li-001",type:"listening",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["听力","介绍"],block:"listening",prompt:"听音频，选出你听到的内容：",audioSrc:"/audio/lesson-05-06.m4a",transcript:"Nice to meet you.",question:"你听到了什么？",options:["Nice to meet you.","How do you do?","How are you?","Good morning."],correctIndex:0,explanation:`【听力辨识】Nice to meet you. = 很高兴认识你。这是初次见面的标准问候。
【区别】How do you do?也是初次见面用语，但更正式。How are you?是问健康状况的日常用语。
【技巧】听关键单词meet和you来识别Nice to meet you这个表达。`},{id:"L05-li-002",type:"listening",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"medium",tags:["听力","国籍"],block:"listening",prompt:"听音频，判断说话人的国籍：",audioSrc:"/audio/lesson-05-06.m4a",transcript:"I am French. I am from Paris.",question:"说话人是哪国人？",options:["法国人","德国人","中国人","日本人"],correctIndex:0,explanation:`【关键信息】①French = 法国人 ②Paris = 巴黎(法国首都)。
【推理】两个线索都指向法国。即使只听懂其中一个也能得出正确答案。
【知识】Paris是法国的首都，就像Beijing是中国的首都。`},{id:"L05-li-003",type:"listening",lessonGroup:"lesson-05-06",lessonNumber:6,difficulty:"medium",tags:["听力","品牌"],block:"listening",prompt:"听音频，回答品牌的国籍：",audioSrc:"/audio/lesson-05-06.m4a",transcript:"It is a Volvo. It is a Swedish car.",question:"Volvo是哪国的品牌？",options:["瑞典","德国","日本","美国"],correctIndex:0,explanation:`【文化知识】Volvo(沃尔沃)是瑞典著名的汽车品牌，以安全著称。
【词汇】Swedish = 瑞典的/瑞典人，Sweden = 瑞典。
【扩展】常见汽车品牌国籍：Volvo(瑞典), Toyota(日本), BMW(德国), Ford(美国)。`},{id:"L05-li-004",type:"listening",lessonGroup:"lesson-05-06",lessonNumber:5,difficulty:"easy",tags:["听力","问候"],block:"listening",prompt:"听音频，选择正确的回答：",audioSrc:"/audio/lesson-05-06.m4a",transcript:"Good morning, Mr. Smith.",question:"听到这句话，你应该回答：",options:["Good morning.","How are you?","Nice to meet you.","I am fine."],correctIndex:0,explanation:`【问候回应】别人说Good morning，你应该同样回答Good morning。问候语通常"原样返回"。
【文化习惯】英语中对称性问候很常见：A说Good morning→B也说Good morning。A说Hello→B也说Hello。`}];export{e as lesson0506Questions};
